def generate_svg(icon_list, base_icons, badges, colors):
    svg = '<?xml version="1.0" encoding="UTF-8"?>\n<svg xmlns="http://www.w3.org/2000/svg">\n<defs>\n'
    for icon in icon_list:
        category = icon["category"]
        color = colors.get(category, "#000000")
        name = icon["name"]
        base = icon["base"]
        badge = icon.get("badge")
        svg += f'<symbol id="{name}" viewBox="0 0 24 24">\n'
        if badge:
            svg += f'<g class="core" stroke="{color}" stroke-width="1.5" stroke-linecap="round" stroke-linejoin="round" fill="none">\n'
            svg += f'<path d="{base_icons[base]}"/>\n'
            svg += '</g>\n'
            svg += f'<g class="badge" stroke="{color}" stroke-width="1.5" stroke-linecap="round" stroke-linejoin="round" fill="none">\n'
            svg += f'<g transform="translate(12,12) scale(0.5)">\n'
            svg += f'<path d="{badges[badge]}"/>\n'
            svg += '</g>\n'
            svg += '</g>\n'
        else:
            svg += f'<g stroke="{color}" stroke-width="1.5" stroke-linecap="round" stroke-linejoin="round" fill="none">\n'
            svg += f'<path d="{base_icons[base]}"/>\n'
            svg += '</g>\n'
        svg += '</symbol>\n'
    svg += '</defs>\n</svg>\n'
    return svg

if __name__ == "__main__":
    svg_content = generate_svg(icon_list, base_icons, badges, colors)
    with open("icon_library/sprite.svg", "w") as f:
        f.write(svg_content)
    print("SVG sprite generated successfully!")